var expect = require('expect.js');
var Rulemanage = require('../../res/page/rulemanage/rulemanage');

describe('sqlscan-rulemanage', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init Rulemanage()', function(){
    it('init Rulemanage', function(done){
      var rulemanage = Rulemanage._create({
        events : {
          'aftercomplete' : function(){
            expect(rulemanage).to.be.ok();
            var grade = this.query('combobox[name=rank]');
            var ruleName = this.query('combobox[name="rulename"]');
            var owner = this.query('combobox[name="owner"]');
            var rank = this.query('combobox[name="rank"]');
            expect(grade).to.be.ok();
            expect(ruleName).to.be.ok();
            expect(owner).to.be.ok();
            expect(rank).to.be.ok();
          },
          'afterrulemanagelistload' : function(){
            var rulemanagelist = this.query('list[name="rulemanagelist"]');
            expect(rulemanagelist).to.be.ok();
            expect(rulemanagelist.data.records.length).to.eql(6);
            done();
          }
        }
      });
    });
  });
  describe('#searchRules events', function(){
    it('searchRules', function(done){
      var rulemanage = Rulemanage._create({
        events : {
          'aftercomplete' : function(){
            var btnSearch = this.query('button[name="btnSearch"]');
            btnSearch.emit('click');
            done();
          },
          'afterrulemanagelistload' : function(){
            var rulemanagelist = this.query('list[name="rulemanagelist"]');
            expect(rulemanagelist).to.be.ok();
            expect(rulemanagelist.data.records.length).to.eql(6);
          }
        }
      });
    });
  });
  describe('#rowClickEvent events', function(){
    it('rowClickEvent', function(done){
      var rulemanage = Rulemanage._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            var rulemanagelist = _self.query('list[name="rulemanagelist"]');
            expect(rulemanagelist).to.be.ok();
            var row = $('.rulemanage-list', rulemanagelist.el).eq(0);
            row.trigger({
              type : 'click',
              target : $('.rule-desc', row)
            });
            expect(this.checkRowClick).to.be.ok();
            row.trigger({
              type : 'click',
              target : $('.rule-desc', row)
            });
            expect(this.checkRowClick).not.to.be.ok();
            row.trigger({
              type : 'click',
              target : $('label', row)
            });
            row.trigger({
              type : 'click',
              target : $('.btnUpdate', row)
            });
            expect(this.checkUpdateRule).not.to.be.ok();
            row.trigger({
              type : 'click',
              target : $('.btnDelete', row)
            });
            done();
          },
          'showauthorizerange' : function(){
            expect(this.win).to.be.ok();
          },
          'beginupdaterule' : function(){
            expect(this.checkUpdateRule).to.be.ok();
          },
          'afterdeleterule' : function(){
             var rulemanagelist = this.query('list[name="rulemanagelist"]');
             expect(rulemanagelist.data.records.length).to.be(6);
             /*var status = this.getActiveStatus();
             expect(status).to.be(0);*/
          }
        }
      });
    });
  });
  describe('#tabclick events', function(){
    it('tabclick', function(done){
      var rulemanage = Rulemanage._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            this.on('afterrulemanagelistload', function(){
              var rulemanagelist = _self.query('list[name="rulemanagelist"]');
              expect(rulemanagelist).to.be.ok();
              expect(rulemanagelist.data.records.length).to.be(6);
            });
            var ftab = $('.rulemanagelist-tab', this.el).children("span:first");
            var stab = $('.rulemanagelist-tab', this.el).children("span:last");
            ftab.trigger('click');
            expect(ftab[0].className).to.be('rulemanagelist-tab-active');
            expect(stab[0].className).to.be('rulemanagelist-tab-deactive');
            stab.trigger('click');
            expect(ftab[0].className).to.be('rulemanagelist-tab-deactive');
            expect(stab[0].className).to.be('rulemanagelist-tab-active');
            done();
          }
        }
      });
    });
  });
});